#include<bits/stdc++.h>
using namespace std;

long long ans = 0;
long long maxx = 0;
int n, m;
long long a[1005][1005];

bool dfs(int x, int y) {
	if (a[x][y] - 1 + x > n || a[x][y] - 1 + y > m) return 0;
	for (int i = 0; i < a[x][y]; i++) {
		for (int j = 0; j < a[x][y]; j++) {
			if(a[i+x][j+y]<a[x][y]){
				return 0;
			}
		}
	}
	return 1;
}
int main(){
	cin>>n>>m;
	for(int i=1;i<=n;i++) for(int j=1;j<=m;j++) cin>>a[i][j],ans+=a[i][j];
	for(int i=1;i<=n;i++) for(int j=1;j<=m;j++) if(dfs(i,j)) maxx=max(maxx,a[i][j]);
	cout<<ans-maxx*maxx*maxx;

	return 0;
}
